SELECT COUNT(lr.PK) FROM LATTES_REG lr JOIN LATTES_P_REG lpr ON lpr.FK_REG = lr.PK JOIN SERVIDOR s ON s.PK_SIAPE = lpr.FK_SIAPE WHERE LOWER(COALESCE(lr.TIPO,'')) = 'software' AND lr.ANO = 2025 AND (LOWER(COALESCE(s.SIGLA_CAMPUS,'')) = 'gyn' OR LOWER(COALESCE(s.CAMPUS_ATUAL,'')) LIKE '%goiania%' OR LOWER(COALESCE(s.CAMPUS_ATUAL,'')) LIKE '%goiania%') AND (LOWER(COALESCE(s.AREA_INGRESSO,'')) LIKE '%ciencia da computacao%' OR LOWER(COALESCE(s.AREA_INGRESSO,'')) LIKE '%ciencia da computacao%')